// Ledger record factory. A record is { id, amountCents }.
function isNonNegInt(n) {
  return typeof n === "number" && Number.isInteger(n) && n >= 0;
}
function make(id, amountCents) {
  if (!isNonNegInt(id)) throw new Error(`invalid id: ${id}`);
  if (!isNonNegInt(amountCents)) throw new Error(`invalid amountCents: ${amountCents}`);
  return { id, amountCents };
}
module.exports = { make };
